import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { UserPlus, Fingerprint, Mail, Lock, Eye, EyeOff } from 'lucide-react';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password) {
      toast.error('Please fill in all fields');
      return;
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center px-4 py-8">
      <div className="w-full max-w-md relative">
        {/* Ambient glow effect */}
        <div className="absolute -top-32 -right-32 w-64 h-64 bg-emerald-600/20 blur-[120px] pointer-events-none" />
        
        <div className="relative z-10 bg-[#141414]/80 backdrop-blur-xl rounded-2xl border border-white/8 shadow-2xl p-8 sm:p-10">
          {/* Header */}
          <div className="text-center mb-8">
            <div className="flex justify-center mb-5">
              <div className="p-4 bg-emerald-500/10 rounded-2xl">
                <UserPlus size={36} className="text-emerald-400 animate-pulse" />
              </div>
            </div>
            <h1 className="text-2xl sm:text-3xl font-light tracking-tight text-white mb-2">
              Create Account
            </h1>
            <p className="text-white/40 text-xs uppercase tracking-widest font-mono">
              Sign up to get started
            </p>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Name */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Fingerprint size={14} /> Full Name
              </label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                className="w-full px-4 py-3.5 rounded-xl bg-white/4 border border-white/8 text-white placeholder-white/20 outline-none transition-all duration-300 focus:border-emerald-500 focus:shadow-[0_0_0_1px_rgba(16,185,129,0.25)]"
                placeholder="John Doe"
                required
              />
            </div>

            {/* Email */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Mail size={14} /> Email Address
              </label>
              <input
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                className="w-full px-4 py-3.5 rounded-xl bg-white/4 border border-white/8 text-white placeholder-white/20 outline-none transition-all duration-300 focus:border-emerald-500 focus:shadow-[0_0_0_1px_rgba(16,185,129,0.25)]"
                placeholder="you@example.com"
                required
              />
            </div>

            {/* Password */}
            <div className="space-y-2">
              <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
                <Lock size={14} /> Password
              </label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  value={formData.password}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                  className="w-full px-4 py-3.5 rounded-xl bg-white/4 border border-white/8 text-white placeholder-white/20 outline-none transition-all duration-300 focus:border-emerald-500 focus:shadow-[0_0_0_1px_rgba(16,185,129,0.25)] pr-12"
                  placeholder="••••••••"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-white/40 hover:text-white/60 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={loading}
              className="w-full py-3.5 px-6 rounded-xl bg-emerald-500 font-semibold uppercase tracking-widest text-xs text-black transition-all duration-300 hover:bg-emerald-400 hover:shadow-[0_0_35px_rgba(16,185,129,0.3)] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed mt-6"
            >
              {loading ? 'Creating account...' : 'Create Account'}
            </button>
          </form>

          {/* Footer */}
          <div className="mt-8 pt-6 border-t border-white/5 text-center">
            <p className="text-xs text-white/40 uppercase tracking-widest">
              Already have an account?{' '}
              <Link to="/login" className="text-emerald-400 hover:underline transition-colors">
                Sign In
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
